    Przykład użycia get_headers z żądaniem HEAD


<?php
// Domyślnie get_headers używa żądania GET do pobrania nagłówków. Aby
// wysłać żądanie HEAD, można użyć kontekstu strumienia:
$context = stream_context_create(
    [
        'http' => array(
            'method' => 'HEAD'
        )
    ]
);
$headers = get_headers('http://example.com', false, $context);
?>
